INSERT INTO spots VALUES('b5d29437-1a28-4d1f-af68-43d39bf6d35e','midoriko','みどり湖','みどりこ','長野県','塩尻市',36.09234200000000214,137.994494000000003,'塩尻市の農業用ため池「みどり湖」を囲む道路をつないで1周約1.6kmの周回コースです。ヘラブナ釣りで知られる静かな湖で、湖畔は公園として整備され、4月上旬には約3800株の水芭蕉が見頃を迎えます。信号のない周回を短い間隔で重ねられるので、ペース走やインターバルの練習にも使えます。湖の南側の堤体付近を中心に緩い起伏があります。釣り人や散策の人と共用の道のため、桟橋や駐車場の周辺では速度を落として走ってください。','JR中央本線 みどり湖駅から東へ約1.5km(徒歩約20分)。長野自動車道 塩尻ICから車で約10分。湖畔に無料駐車場(約50台)あり',1,0,0,0,0,0,1,0,'dark',NULL,1,1784432077000,1784432077562);
